# lib/my_app_web/xml/safe_parser.ex
defmodule MyAppWeb.Xml.SafeParser do
  @moduledoc """
  Safely parses XML with external entities DISABLED to prevent XXE attacks.
  """

  import SweetXml

  @doc """
  Parses XML string safely by disabling DTD and external entity processing.
  Returns {:ok, parsed} or {:error, reason}.
  """
  def safe_parse(xml_string) when is_binary(xml_string) do
    # Reject XML that contains DOCTYPE declarations to prevent XXE
    if contains_dangerous_declarations?(xml_string) do
      {:error, :potentially_malicious_xml}
    else
      try do
        # Use SweetXml with xmerl options that disable external entities
        parsed =
          xml_string
          |> SweetXml.parse(
            dtd: :none,
            quiet: true
          )

        {:ok, parsed}
      rescue
        e -> {:error, {:parse_error, Exception.message(e)}}
      catch
        :exit, reason -> {:error, {:parse_error, inspect(reason)}}
      end
    end
  end

  @doc """
  Safely parses XML and extracts values using xpath.
  """
  def safe_xpath(xml_string, xpath_expr) do
    case safe_parse(xml_string) do
      {:ok, doc} ->
        try do
          result = SweetXml.xpath(doc, xpath_expr)
          {:ok, result}
        rescue
          e -> {:error, {:xpath_error, Exception.message(e)}}
        end

      {:error, _} = error ->
        error
    end
  end

  @doc """
  Safely parses XML and extracts multiple values using xmap.
  """
  def safe_xmap(xml_string, mapping) do
    case safe_parse(xml_string) do
      {:ok, doc} ->
        try do
          result = SweetXml.xmap(doc, mapping)
          {:ok, result}
        rescue
          e -> {:error, {:xpath_error, Exception.message(e)}}
        end

      {:error, _} = error ->
        error
    end
  end

  # Check for dangerous XML declarations that could enable XXE
  defp contains_dangerous_declarations?(xml_string) do
    xml_lower = String.downcase(xml_string)

    String.contains?(xml_lower, "<!doctype") or
      String.contains?(xml_lower, "<!entity") or
      String.contains?(xml_lower, "system") or
      String.contains?(xml_lower, "<!element") or
      Regex.match?(~r/<!DOCTYPE/i, xml_string) or
      Regex.match?(~r/<!ENTITY/i, xml_string)
  end
end

# lib/my_app_web/controllers/soap_controller.ex
defmodule MyAppWeb.SoapController do
  use MyAppWeb, :controller

  import SweetXml

  alias MyAppWeb.Xml.SafeParser

  @doc """
  Handle incoming SOAP requests.
  """
  def handle(conn, %{"_xml" => xml_body}) do
    # Define the SOAP envelope namespaces
    with {:ok, request_data} <- parse_soap_request(xml_body),
         {:ok, response} <- process_soap_action(conn, request_data) do
      conn
      |> put_resp_content_type("text/xml")
      |> send_resp(200, build_soap_response(response))
    else
      {:error, :potentially_malicious_xml} ->
        conn
        |> put_resp_content_type("text/xml")
        |> send_resp(400, build_soap_fault("Client", "Malicious XML detected. DTD and external entities are not allowed."))

      {:error, {:parse_error, reason}} ->
        conn
        |> put_resp_content_type("text/xml")
        |> send_resp(400, build_soap_fault("Client", "Invalid XML: #{reason}"))

      {:error, reason} ->
        conn
        |> put_resp_content_type("text/xml")
        |> send_resp(500, build_soap_fault("Server", "Internal error: #{inspect(reason)}"))
    end
  end

  def handle(conn, _params) do
    conn
    |> put_resp_content_type("text/xml")
    |> send_resp(400, build_soap_fault("Client", "Request body must be XML"))
  end

  defp parse_soap_request(xml_body) do
    SafeParser.safe_xmap(xml_body, [
      soap_action: ~x"//soap:Envelope/soap:Body/*[1]"e
        |> add_namespace("soap", "http://schemas.xmlsoap.org/soap/envelope/"),
      # Example: extract specific fields from the SOAP body
      method_name: ~x"//soap:Envelope/soap:Body/*[1]/local-name()"s
        |> add_namespace("soap", "http://schemas.xmlsoap.org/soap/envelope/"),
    ])
  end

  defp process_soap_action(conn, %{soap_action: action_element} = request_data) do
    # Get the SOAP action from the header or body
    soap_action = get_req_header(conn, "soapaction") |> List.first()

    # Route to appropriate handler based on SOAP action
    case soap_action || request_data[:method_name] do
      action when action in ["GetUser", "\"GetUser\""] ->
        handle_get_user(action_element)

      action when action in ["CreateOrder", "\"CreateOrder\""] ->
        handle_create_order(action_element)

      action when action in ["GetStatus", "\"GetStatus\""] ->
        handle_get_status(action_element)

      unknown ->
        {:error, "Unknown SOAP action: #{inspect(unknown)}"}
    end
  end

  defp handle_get_user(action_element) do
    # Safely extract data using xpath on already-parsed (safe) element
    user_id = SweetXml.xpath(action_element, ~x"./UserId/text()"s)

    {:ok, %{
      action: "GetUserResponse",
      body: """
      <GetUserResponse xmlns="http://example.com/soap">
        <User>
          <Id>#{escape_xml(user_id)}</Id>
          <Name>John Doe</Name>
          <Email>john@example.com</Email>
        </User>
      </GetUserResponse>
      """
    }}
  end

  defp handle_create_order(action_element) do
    product_id = SweetXml.xpath(action_element, ~x"./ProductId/text()"s)
    quantity = SweetXml.xpath(action_element, ~x"./Quantity/text()"s)

    {:ok, %{
      action: "CreateOrderResponse",
      body: """
      <CreateOrderResponse xmlns="http://example.com/soap">
        <OrderId>ORD-12345</OrderId>
        <ProductId>#{escape_xml(product_id)}</ProductId>
        <Quantity>#{escape_xml(quantity)}</Quantity>
        <Status>Created</Status>
      </CreateOrderResponse>
      """
    }}
  end

  defp handle_get_status(action_element) do
    order_id = SweetXml.xpath(action_element, ~x"./OrderId/text()"s)

    {:ok, %{
      action: "GetStatusResponse",
      body: """
      <GetStatusResponse xmlns="http://example.com/soap">
        <OrderId>#{escape_xml(order_id)}</OrderId>
        <Status>Processing</Status>
      </GetStatusResponse>
      """
    }}
  end

  defp build_soap_response(%{body: body}) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Header/>
      <soap:Body>
        #{body}
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp build_soap_fault(fault_code, fault_string) do
    """
    <?xml version="1.0" encoding="UTF-8"?>
    <soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
      <soap:Body>
        <soap:Fault>
          <faultcode>soap:#{fault_code}</faultcode>
          <faultstring>#{escape_xml(fault_string)}</faultstring>
        </soap:Fault>
      </soap:Body>
    </soap:Envelope>
    """
  end

  defp escape_xml(string) when is_binary(string) do
    string
    |> String.replace("&", "&amp;")
    |> String.replace("<", "&lt;")
    |> String.replace(">", "&gt;")
    |> String.replace("\"", "&quot;")
    |> String.replace("'", "&apos;")
  end

  defp escape_xml(other), do: escape_xml(to_string(other))
end

